#include <iostream>
#include <optional>

std::optional<long long> safe_square(long long value) {
    if (value < -1000000 || value > 1000000) return std::nullopt;
    return value * value;
}

int main() {
    long long value{};
    if (!(std::cin >> value)) return 1;
    if (auto result = safe_square(value)) std::cout << *result << '\n';
    else std::cout << "invalid\n";
}
